-- ============================================================================
-- Quiz Seed: 1 Kings — Part 1 (Chapters 1–11)
-- 3 kids + 5 teens + 8 adults = 16 questions × 11 chapters = 176 total questions
-- ============================================================================

-- ═══ 1 Kings Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Kings', 1, 'kids', 1, 'Who tried to make himself king while David was old?', 'Adonijah', 'Solomon', 'Joab', 'Nathan', 'a', '1 Kings 1:5 — "Then Adonijah the son of Haggith exalted himself, saying, I will be king."'),
('1 Kings', 1, 'kids', 2, 'Who did King David choose to be the next king of Israel?', 'Solomon', 'Adonijah', 'Absalom', 'Joab', 'a', '1 Kings 1:30 — "Even so will I certainly do this day." David confirmed Solomon as king.'),
('1 Kings', 1, 'kids', 3, 'Where was Solomon taken to be anointed as king?', 'Gihon', 'Jerusalem', 'Bethlehem', 'Hebron', 'a', '1 Kings 1:33 — "The king said...cause Solomon my son to ride upon mine own mule, and bring him down to Gihon."'),
-- Teens
('1 Kings', 1, 'teens', 1, 'Who were the two people who went to King David to report Adonijah''s attempt to take the throne?', 'Nathan and Bathsheba', 'Joab and Abiathar', 'Zadok and Benaiah', 'Shimei and Abishai', 'a', '1 Kings 1:11 — "Wherefore Nathan spake unto Bathsheba the mother of Solomon," and they together approached King David.'),
('1 Kings', 1, 'teens', 2, 'Which priest anointed Solomon as king at Gihon?', 'Zadok', 'Abiathar', 'Eli', 'Ahimelech', 'a', '1 Kings 1:39 — "And Zadok the priest took an horn of oil out of the tabernacle, and anointed Solomon."'),
('1 Kings', 1, 'teens', 3, 'What did Adonijah do when he heard that Solomon had been anointed king?', 'He fled the country', 'He caught hold on the horns of the altar', 'He gathered an army to fight', 'He went into hiding', 'a', '1 Kings 1:50 — "And Adonijah feared because of Solomon, and arose, and went, and caught hold on the horns of the altar."'),
('1 Kings', 1, 'teens', 4, 'Which notable supporters did Adonijah NOT have on his side?', 'Zadok the priest and Benaiah and Nathan', 'Joab and Abiathar', 'The men of Judah', 'The king''s servants', 'a', '1 Kings 1:26 — "But me, even me thy servant, and Zadok the priest, and Benaiah...and thy servant Solomon, hath he not called."'),
('1 Kings', 1, 'teens', 5, 'What was the name of the young woman brought to minister to the aged King David?', 'Abishag', 'Bathsheba', 'Rizpah', 'Tamar', 'a', '1 Kings 1:3 — "And they found Abishag a Shunammite, and brought her to the king."'),
-- Adults
('1 Kings', 1, 'adults', 1, 'What condition prompted David''s servants to seek a young woman to minister to the king?', 'He could get no heat though they covered him with clothes', 'He was bedridden with a fever', 'He had lost his sight', 'He was unable to eat', 'a', '1 Kings 1:1 — "Now king David was old and stricken in years; and they covered him with clothes, but he gat no heat."'),
('1 Kings', 1, 'adults', 2, 'Adonijah''s attempt to seize the throne echoes which earlier sibling''s pattern?', 'Absalom, who also prepared chariots and horsemen', 'Amnon, who was firstborn', 'Shephatiah, the third son', 'Chileab, who died young', 'a', '1 Kings 1:5-6 — "He prepared him chariots and horsemen...And his mother bare him after Absalom," mirroring Absalom''s earlier rebellion.'),
('1 Kings', 1, 'adults', 3, 'What specific oath had David sworn to Bathsheba that Nathan referenced to spur his intervention?', 'That Solomon would reign after him and sit upon his throne', 'That her son would be high priest', 'That Solomon would build the temple', 'That Bathsheba would be queen mother', 'a', '1 Kings 1:13 — "Didst not thou, my lord, O king, swear unto thine handmaid, saying, Assuredly Solomon thy son shall reign after me, and he shall sit upon my throne?"'),
('1 Kings', 1, 'adults', 4, 'What instruments and shout accompanied Solomon''s anointing procession?', 'Pipes, and the people rejoiced with great joy so the earth rent', 'Trumpets and cymbals and harps', 'Tabrets and psalteries and singing', 'Horns and drums and dancing', 'a', '1 Kings 1:40 — "And all the people came up after him, and the people piped with pipes, and rejoiced with great joy, so that the earth rent with the sound of them."'),
('1 Kings', 1, 'adults', 5, 'On what condition did Solomon allow Adonijah to live after he held the altar?', 'If he showed himself a worthy man, no hair of him would fall', 'If he left Jerusalem immediately', 'If he swore an oath before Zadok', 'If he renounced all claim to the throne publicly', 'a', '1 Kings 1:52 — "If he will shew himself a worthy man, there shall not an hair of him fall to the earth: but if wickedness shall be found in him, he shall die."'),
('1 Kings', 1, 'adults', 6, 'What did Joab''s support of Adonijah reveal about the political alignment at David''s court?', 'A faction of the old military guard backed Adonijah while the prophetic and priestly circle backed Solomon', 'All the court unanimously supported Adonijah', 'The Levites alone opposed Adonijah', 'Joab acted alone without allies', 'a', '1 Kings 1:7 — "And he conferred with Joab the son of Zeruiah, and with Abiathar the priest: and they following Adonijah helped him."'),
('1 Kings', 1, 'adults', 7, 'What was the name of the feast Adonijah held where he proclaimed himself king?', 'A sacrificial feast at En-rogel with sheep, oxen, and fat cattle', 'A Passover feast at Gibeon', 'A peace offering at Bethel', 'A new moon feast at Hebron', 'a', '1 Kings 1:9 — "And Adonijah slew sheep and oxen and fat cattle by the stone of Zoheleth, which is by En-rogel."'),
('1 Kings', 1, 'adults', 8, 'What was David''s blessing upon Solomon when he charged him from his bed?', 'Blessed be the LORD God of Israel, which hath given one to sit on my throne this day, mine eyes even seeing it', 'The LORD make thee wise above all men', 'Keep the commandments and thou shalt prosper', 'Go in peace and rule with justice', 'a', '1 Kings 1:48 — "And also thus said the king, Blessed be the LORD God of Israel, which hath given one to sit on my throne this day, mine eyes even seeing it."');

-- ═══ 1 Kings Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Kings', 2, 'kids', 1, 'What did King David tell Solomon to do before he died?', 'Keep the commandments of the LORD', 'Build a great palace', 'Make war on all enemies', 'Plant vineyards and gardens', 'a', '1 Kings 2:3 — "And keep the charge of the LORD thy God, to walk in his ways, to keep his statutes, and his commandments."'),
('1 Kings', 2, 'kids', 2, 'What happened to Adonijah when he asked for Abishag to be his wife?', 'Solomon had him put to death', 'Solomon gave him Abishag', 'Solomon sent him into exile', 'Solomon forgave him completely', 'a', '1 Kings 2:25 — "And king Solomon sent by the hand of Benaiah...and he fell upon him that he died."'),
('1 Kings', 2, 'kids', 3, 'Where did Joab flee when he knew Solomon was after him?', 'Into the tabernacle to hold the horns of the altar', 'Into the wilderness', 'To another king', 'Into a cave', 'a', '1 Kings 2:28 — "Then tidings came to Joab: for Joab had turned after Adonijah...and Joab fled unto the tabernacle of the LORD, and caught hold on the horns of the altar."'),
-- Teens
('1 Kings', 2, 'teens', 1, 'What promise did David remind Solomon to fulfil regarding the sons of Barzillai the Gileadite?', 'Let them eat at Solomon''s table because they showed kindness to David', 'Give them land in Judah as a reward', 'Make one of them a commander in the army', 'Pay them the wages David had owed them', 'a', '1 Kings 2:7 — "But shew kindness unto the sons of Barzillai the Gileadite, and let them be of those that eat at thy table."'),
('1 Kings', 2, 'teens', 2, 'For what act did David charge Solomon to deal wisely with Joab?', 'Joab had shed the blood of war in peace, killing Abner and Amasa', 'Joab had stolen from the royal treasury', 'Joab had conspired with foreign kings', 'Joab had burned the harvest fields', 'a', '1 Kings 2:5 — "Moreover thou knowest also what Joab the son of Zeruiah did to me...how he shed the blood of war in peace, and put the blood of war upon his girdle."'),
('1 Kings', 2, 'teens', 3, 'Why did Solomon consider Adonijah''s request for Abishag treasonous?', 'Asking for the king''s woman was equivalent to asking for the kingdom', 'Abishag was Solomon''s betrothed', 'Abishag was a royal priestess', 'It violated a covenant David had made', 'a', '1 Kings 2:22 — "And why dost thou ask Abishag the Shunammite for Adonijah? ask for him the kingdom also; for he is mine elder brother."'),
('1 Kings', 2, 'teens', 4, 'How many years did Shimei live peacefully in Jerusalem before he violated Solomon''s oath?', 'Three years', 'Two years', 'Five years', 'One year', 'a', '1 Kings 2:39 — "And it came to pass at the end of three years, that two of the servants of Shimei ran away."'),
('1 Kings', 2, 'teens', 5, 'What condition had Solomon set for Shimei''s life to be spared?', 'He must not cross the brook Kidron', 'He must dwell in Jerusalem and not go elsewhere on pain of death', 'He must serve in the temple', 'He must pay a yearly tribute', 'a', '1 Kings 2:36-37 — "Build thee an house in Jerusalem, and dwell there...For it shall be, that on the day thou goest out...thou shalt know for certain that thou shalt surely die."'),
-- Adults
('1 Kings', 2, 'adults', 1, 'What theological framework did David give Solomon for his reign in his final charge?', 'Walk in God''s ways, keep His statutes and commandments as written in the law of Moses, so the LORD may continue His word', 'Build the temple and offer sacrifices daily', 'Conquer all surrounding nations to secure the kingdom', 'Maintain alliances with Hiram and Egypt', 'a', '1 Kings 2:3 — "Keep the charge of the LORD thy God, to walk in his ways...as it is written in the law of Moses, that thou mayest prosper in all that thou doest."'),
('1 Kings', 2, 'adults', 2, 'What specific dynastic promise did David remind Solomon of concerning God''s covenant?', 'There shall not fail thee a man on the throne of Israel if thy children walk before God in truth with all their heart', 'The kingdom shall stand forever unconditionally', 'Ten tribes would always remain loyal', 'The temple would never be destroyed', 'a', '1 Kings 2:4 — "That the LORD may continue his word which he spake concerning me, saying, If thy children take heed to their way, to walk before me in truth with all their heart."'),
('1 Kings', 2, 'adults', 3, 'What was Abiathar''s punishment for supporting Adonijah, and why was he not executed?', 'He was thrust out of the priesthood but spared because he had borne the ark before David', 'He was imprisoned for life', 'He was exiled to a foreign land', 'He was demoted to a minor temple role', 'a', '1 Kings 2:26-27 — "And unto Abiathar the priest said the king, Get thee to Anathoth...because thou barest the ark of the Lord GOD before David."'),
('1 Kings', 2, 'adults', 4, 'How did Benaiah execute Joab inside the tabernacle, and what scripture rationale did Solomon give?', 'He killed him there, removing innocent blood from Israel and David''s house that Joab had shed', 'He dragged him outside first at Solomon''s command', 'He waited for a priest''s permission', 'He offered Joab a last chance to surrender', 'a', '1 Kings 2:31-33 — "Go fall upon him...that thou mayest take away the innocent blood...from David, and from his seed, and from his house, and from his throne, for ever."'),
('1 Kings', 2, 'adults', 5, 'How did Solomon''s removal of Abiathar fulfil an earlier prophecy?', 'It fulfilled God''s word spoken concerning Eli''s house at Shiloh', 'It fulfilled Nathan''s oracle given during David''s reign', 'It fulfilled Moses'' warning about corrupt priests', 'It fulfilled Samuel''s last prophecy', 'a', '1 Kings 2:27 — "So Solomon thrust out Abiathar from being priest unto the LORD; that he might fulfil the word of the LORD, which he spake concerning the house of Eli in Shiloh."'),
('1 Kings', 2, 'adults', 6, 'What did Shimei do that violated his oath and led to his death?', 'He went to Gath to bring back two runaway servants', 'He spoke against Solomon publicly', 'He attempted to leave Israel', 'He harboured enemies of the king', 'a', '1 Kings 2:40 — "And Shimei arose, and saddled his ass, and went to Gath to Achish to seek his servants: and Shimei went, and brought his servants from Gath."'),
('1 Kings', 2, 'adults', 7, 'How does the summary verse close the account of Solomon''s consolidation of power?', 'So the kingdom was established in the hand of Solomon', 'And there was peace throughout all Israel', 'Solomon reigned in wisdom and justice from that day', 'The LORD blessed Solomon above all kings', 'a', '1 Kings 2:46 — "So the king commanded Benaiah the son of Jehoiada; which went out, and fell upon him, that he died. And the kingdom was established in the hand of Solomon."'),
('1 Kings', 2, 'adults', 8, 'What legal principle did Solomon invoke from Moses'' law when ordering Shimei''s death?', 'The guilty person who commits evil shall bear their own iniquity, and the curse returns on their own head', 'Two witnesses are required before any execution', 'No man shall be put to death for his father''s sins', 'The king''s word is law above Mosaic statute', 'a', '1 Kings 2:44-45 — "The LORD shall return thy wickedness upon thine own head...And king Solomon shall be blessed, and the throne of David shall be established before the LORD for ever."');

-- ═══ 1 Kings Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Kings', 3, 'kids', 1, 'What did Solomon ask God to give him?', 'An understanding heart to judge the people', 'Great riches and gold', 'A long life', 'Victory over his enemies', 'a', '1 Kings 3:9 — "Give therefore thy servant an understanding heart to judge thy people, that I may discern between good and bad."'),
('1 Kings', 3, 'kids', 2, 'Two women both claimed a baby was theirs. What did Solomon say he would do to find the truth?', 'Divide the living child in two with a sword', 'Ask the women to take an oath', 'Pray for God to reveal the true mother', 'Watch which woman the baby reached for', 'a', '1 Kings 3:25 — "And the king said, Divide the living child in two, and give half to the one, and half to the other."'),
('1 Kings', 3, 'kids', 3, 'Who was the real mother revealed to be?', 'The woman who said do not kill the child', 'The woman who agreed to divide the child', 'The oldest woman', 'The woman who wept louder', 'a', '1 Kings 3:27 — "Then the king answered and said, Give her the living child, and in no wise slay it: she is the mother thereof."'),
-- Teens
('1 Kings', 3, 'teens', 1, 'Where did God appear to Solomon in a dream at the start of chapter 3?', 'Gibeon', 'Jerusalem', 'Bethel', 'Shiloh', 'a', '1 Kings 3:5 — "In Gibeon the LORD appeared to Solomon in a dream by night: and God said, Ask what I shall give thee."'),
('1 Kings', 3, 'teens', 2, 'What did Solomon acknowledge about himself when God invited him to ask for anything?', 'He was a little child and knew not how to go out or come in', 'He lacked military strength', 'He had not yet built the temple', 'He was younger than all the kings around him', 'a', '1 Kings 3:7 — "And now, O LORD my God, thou hast made thy servant king instead of David my father: and I am but a little child: I know not how to go out or come in."'),
('1 Kings', 3, 'teens', 3, 'Because Solomon asked for wisdom rather than riches or long life, what else did God promise to give him?', 'Riches and honour, so there shall not be any among kings like him all his days', 'Victory over all his enemies', 'A son to rule after him', 'The love of all the nations', 'a', '1 Kings 3:13 — "And I have also given thee that which thou hast not asked, both riches, and honour: so that there shall not be any among the kings like unto thee all thy days."'),
('1 Kings', 3, 'teens', 4, 'What did Solomon offer when he returned to Jerusalem after God''s appearance at Gibeon?', 'Burnt offerings and peace offerings before the ark, and a feast for all his servants', 'A prayer of thanksgiving at the high place', 'A proclamation of fasting throughout Israel', 'Silver and gold to the priests', 'a', '1 Kings 3:15 — "And Solomon awoke; and, behold, it was a dream...and he offered up burnt offerings, and offered peace offerings, and made a feast to all his servants."'),
('1 Kings', 3, 'teens', 5, 'What was the key difference in how the two harlot mothers reacted to Solomon''s sword verdict?', 'The true mother pleaded to spare the child while the other agreed to divide him', 'One wept and one laughed', 'One fled the court and one stayed', 'One called witnesses and one was silent', 'a', '1 Kings 3:26 — "Then spake the woman whose the living child was...for her bowels yearned upon her son, and she said, O my lord, give her the living child, and in no wise slay it: but the other said, Let it be neither mine nor thine, but divide it."'),
-- Adults
('1 Kings', 3, 'adults', 1, 'What political alliance did Solomon make at the opening of chapter 3, and what was its theological note?', 'He made affinity with Pharaoh king of Egypt, though the people still sacrificed at high places because no house for the LORD was built yet', 'He made a treaty with Hiram of Tyre', 'He allied with the king of Moab', 'He married a daughter of the king of Syria', 'a', '1 Kings 3:1-2 — "And Solomon made affinity with Pharaoh king of Egypt...Only the people sacrificed in high places, because there was no house built unto the name of the LORD."'),
('1 Kings', 3, 'adults', 2, 'What specific description of David does Solomon use to ground his own unworthiness before God?', 'David walked before God in truth and righteousness and uprightness of heart', 'David was a man after God''s own heart', 'David kept all the commandments perfectly', 'David had built the altar at Gibeon', 'a', '1 Kings 3:6 — "Thou hast shewed unto thy servant David my father great mercy, according as he walked before thee in truth, and in righteousness, and in uprightness of heart with thee."'),
('1 Kings', 3, 'adults', 3, 'What was the nature of Solomon''s request — what exact phrase did he use for the gift he sought?', 'A hearing heart to judge God''s people, to discern between good and bad', 'Wisdom surpassing all other kings', 'Knowledge of God''s hidden mysteries', 'Discernment of every legal dispute', 'a', '1 Kings 3:9 — "Give therefore thy servant an understanding heart to judge thy people, that I may discern between good and bad: for who is able to judge this thy so great a people?"'),
('1 Kings', 3, 'adults', 4, 'What was the condition God attached to His promise of long life for Solomon?', 'If Solomon would walk in God''s ways, keep His statutes and commandments as David had done', 'If Solomon would build the temple within ten years', 'If Solomon would not intermarry with foreign nations', 'If Solomon would not raise taxes on the people', 'a', '1 Kings 3:14 — "And if thou wilt walk in my ways, to keep my statutes and my commandments, as thy father David did walk, then I will lengthen thy days."'),
('1 Kings', 3, 'adults', 5, 'What was the situation of the two harlots'' babies at the heart of the dispute Solomon had to judge?', 'One baby had died in the night when his mother overlaid him, and each woman claimed the living child', 'One baby had been stolen from the market', 'One baby was sick and both claimed to be the true mother', 'One baby had been swapped at birth in the palace', 'a', '1 Kings 3:19-20 — "And this woman''s child died in the night; because she overlaid it...And she arose at midnight...and took my son from beside me."'),
('1 Kings', 3, 'adults', 6, 'What was the reaction of all Israel to Solomon''s judgment in this case?', 'They feared the king, for they saw that the wisdom of God was in him to do judgment', 'They praised God in the temple', 'They marvelled but were uncertain of the verdict', 'They compared him favourably to David', 'a', '1 Kings 3:28 — "And all Israel heard of the judgment which the king had judged; and they feared the king: for they saw that the wisdom of God was in him, to do judgment."'),
('1 Kings', 3, 'adults', 7, 'What does God''s offer "Ask what I shall give thee" reveal about the nature of this divine encounter?', 'It was an open invitation testing Solomon''s character and priorities before his reign was confirmed', 'It was a routine blessing given to every new king', 'It was a test that all kings of Israel had to pass', 'It was a limited offer only available at Gibeon', 'a', '1 Kings 3:5 — "In Gibeon the LORD appeared to Solomon in a dream by night: and God said, Ask what I shall give thee," revealing God''s desire to know Solomon''s heart.'),
('1 Kings', 3, 'adults', 8, 'What does Solomon''s description of Israel as "a great people, that cannot be numbered nor counted for multitude" recall?', 'The Abrahamic promise of descendants as numerous as stars and sand', 'The census taken by David', 'The population count of the Exodus generation', 'The prophecy of Balaam', 'a', '1 Kings 3:8 — "And thy servant is in the midst of thy people which thou hast chosen, a great people, that cannot be numbered nor counted for multitude," echoing Genesis 15:5 and 22:17.');

-- ═══ 1 Kings Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Kings', 4, 'kids', 1, 'How many proverbs did Solomon speak?', 'Three thousand', 'One thousand', 'Five hundred', 'Ten thousand', 'a', '1 Kings 4:32 — "And he spake three thousand proverbs: and his songs were a thousand and five."'),
('1 Kings', 4, 'kids', 2, 'How many songs did Solomon compose?', 'A thousand and five', 'Two thousand', 'Three hundred', 'Seven hundred', 'a', '1 Kings 4:32 — "His songs were a thousand and five."'),
('1 Kings', 4, 'kids', 3, 'What did Solomon know about that showed his great wisdom about nature?', 'Trees, beasts, fowl, creeping things, and fishes', 'The stars and their names', 'The languages of all nations', 'The secrets of the deep sea', 'a', '1 Kings 4:33 — "And he spake of trees...he spake also of beasts, and of fowl, and of creeping things, and of fishes."'),
-- Teens
('1 Kings', 4, 'teens', 1, 'How many officers did Solomon have who provided for the king and his household each month?', 'Twelve officers over all Israel', 'Seven officers', 'Forty officers', 'Twenty-four officers', 'a', '1 Kings 4:7 — "And Solomon had twelve officers over all Israel, which provided victuals for the king and his household: each man his month in a year made provision."'),
('1 Kings', 4, 'teens', 2, 'How many men did Solomon have who were in charge of his chariots and horsemen?', 'Forty thousand stalls of horses for his chariots, and twelve thousand horsemen', 'Twenty thousand chariots and ten thousand horsemen', 'Thirty thousand horses and eight thousand riders', 'Fifty thousand horses in all Israel', 'a', '1 Kings 4:26 — "And Solomon had forty thousand stalls of horses for his chariots, and twelve thousand horsemen."'),
('1 Kings', 4, 'teens', 3, 'Whose wisdom was Solomon''s wisdom said to excel?', 'All the children of the east, and all the wisdom of Egypt', 'The wisdom of the Babylonians', 'The wisdom of the Greeks', 'The wisdom of the Persians', 'a', '1 Kings 4:30 — "And Solomon''s wisdom excelled the wisdom of all the children of the east country, and all the wisdom of Egypt."'),
('1 Kings', 4, 'teens', 4, 'What description is given about the daily provision for Solomon''s household?', 'Thirty measures of fine flour and threescore measures of meal, ten fat oxen, and fourscore oxen', 'One hundred sheep daily and an equal number of cattle', 'Twelve oxen and a hundred sheep for each officer', 'A daily feast of seven courses for the whole court', 'a', '1 Kings 4:22-23 — "And Solomon''s provision for one day was thirty measures of fine flour, and threescore measures of meal, ten fat oxen, and twenty oxen out of the pastures, and an hundred sheep."'),
('1 Kings', 4, 'teens', 5, 'How far did Solomon''s dominion extend according to chapter 4?', 'From the river unto the land of the Philistines, and unto the border of Egypt', 'From the Euphrates to the Nile', 'From Dan to Beersheba', 'From Hebron to Damascus', 'a', '1 Kings 4:21 — "And Solomon reigned over all kingdoms from the river unto the land of the Philistines, and unto the border of Egypt."'),
-- Adults
('1 Kings', 4, 'adults', 1, 'Who was Solomon''s chief priest according to the list of officers in chapter 4?', 'Azariah the son of Zadok', 'Abiathar', 'Zadok himself', 'Elihoreph', 'a', '1 Kings 4:2 — "And these were the princes which he had; Azariah the son of Zadok the priest."'),
('1 Kings', 4, 'adults', 2, 'Who were the scribes or secretaries in Solomon''s administration?', 'Elihoreph and Ahiah, the sons of Shisha', 'Azariah son of Nathan', 'Jehoshaphat the son of Ahilud', 'Adoniram son of Abda', 'a', '1 Kings 4:3 — "Elihoreph and Ahiah, the sons of Shisha, scribes."'),
('1 Kings', 4, 'adults', 3, 'What phrase describes the security and prosperity of Israel during Solomon''s reign?', 'Judah and Israel dwelt safely, every man under his vine and under his fig tree', 'There was no war in all the land for forty years', 'The people rejoiced in abundance and praised the king', 'Israel was the mightiest nation under heaven', 'a', '1 Kings 4:25 — "And Judah and Israel dwelt safely, every man under his vine and under his fig tree, from Dan even to Beersheba, all the days of Solomon."'),
('1 Kings', 4, 'adults', 4, 'What was the measure of fodder required daily for Solomon''s horses and other riding animals?', 'Barley and straw for the horses and dromedaries brought to each officer''s place', 'Ten thousand bushels of grain for each stable', 'A daily delivery of twenty cartloads of hay', 'Threescore carts of fodder from the royal granaries', 'a', '1 Kings 4:28 — "Barley also and straw for the horses and dromedaries brought they unto the place where the officers were, every man according to his charge."'),
('1 Kings', 4, 'adults', 5, 'Which four wise men were listed by name as being surpassed by Solomon''s wisdom?', 'Ethan the Ezrahite, and Heman, and Chalcol, and Darda, the sons of Mahol', 'Ahithophel, Hushai, Joab, and Abner', 'Hiram of Tyre, the Queen of Sheba, the wise men of Egypt, and Balaam', 'Isaiah, Jeremiah, Ezekiel, and Daniel', 'a', '1 Kings 4:31 — "For he was wiser than all men; than Ethan the Ezrahite, and Heman, and Chalcol, and Darda, the sons of Mahol."'),
('1 Kings', 4, 'adults', 6, 'What does the phrase "God gave Solomon wisdom and understanding exceeding much" imply about the source of his knowledge?', 'His wisdom was a divine gift, not a natural or acquired human achievement', 'He studied wisdom from Egyptian scrolls', 'He inherited David''s wisdom through lineage', 'He gained wisdom through military campaigns', 'a', '1 Kings 4:29 — "And God gave Solomon wisdom and understanding exceeding much, and largeness of heart, even as the sand that is on the sea shore."'),
('1 Kings', 4, 'adults', 7, 'How many nations sent tribute and served Solomon throughout his reign?', 'All kingdoms from the Euphrates to Egypt brought presents and served Solomon all his days', 'Seven vassal kingdoms paid tribute annually', 'Twelve nations sent gold and silver', 'Twenty-four governors collected tribute', 'a', '1 Kings 4:21 — "And Solomon reigned over all kingdoms from the river...and they brought presents, and served Solomon all the days of his life."'),
('1 Kings', 4, 'adults', 8, 'What does "largeness of heart" mean in the context of 1 Kings 4:29?', 'An expansive capacity of mind and understanding, like the sand of the sea in breadth', 'Generosity toward the poor', 'A compassionate ruling style', 'Physical stamina for royal duties', 'a', '1 Kings 4:29 — "And God gave Solomon wisdom and understanding exceeding much, and largeness of heart, even as the sand that is on the sea shore."');

-- ═══ 1 Kings Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Kings', 5, 'kids', 1, 'Who was the king that sent cedar trees and workers to help Solomon build the temple?', 'Hiram king of Tyre', 'Pharaoh king of Egypt', 'Hadad king of Edom', 'Rezon king of Syria', 'a', '1 Kings 5:1 — "And Hiram king of Tyre sent his servants unto Solomon; for he had heard that they had anointed him king in the room of his father."'),
('1 Kings', 5, 'kids', 2, 'What two kinds of wood did Hiram send to Solomon?', 'Cedar trees and fir trees', 'Oak trees and olive trees', 'Pine trees and palm trees', 'Cypress trees and acacia trees', 'a', '1 Kings 5:10 — "So Hiram gave Solomon cedar trees and fir trees according to all his desire."'),
('1 Kings', 5, 'kids', 3, 'What did Solomon give Hiram in return for the wood?', 'Food — wheat and oil every year', 'Gold and silver', 'Horses and chariots', 'Land in Israel', 'a', '1 Kings 5:11 — "And Solomon gave Hiram twenty thousand measures of wheat for food to his household, and twenty measures of pure oil."'),
-- Teens
('1 Kings', 5, 'teens', 1, 'Why was David unable to build the temple during his own lifetime?', 'Because of the wars David had waged, the blood upon his hands', 'Because he lacked sufficient materials', 'Because God had not yet revealed the temple plans', 'Because the people of Israel were not yet settled', 'a', '1 Kings 5:3 — "Thou knowest how that David my father could not build an house unto the name of the LORD his God for the wars which were about him on every side."'),
('1 Kings', 5, 'teens', 2, 'How many men did Solomon raise as a levy out of all Israel to work in Lebanon?', 'Thirty thousand men', 'Ten thousand men', 'Fifty thousand men', 'Twenty thousand men', 'a', '1 Kings 5:13 — "And king Solomon raised a levy out of all Israel; and the levy was thirty thousand men."'),
('1 Kings', 5, 'teens', 3, 'How were the thirty thousand levy workers scheduled in Lebanon?', 'Ten thousand a month in shifts — one month in Lebanon and two months at home', 'All thirty thousand went at once for three months', 'They rotated weekly in groups of one thousand', 'They each served six months and returned', 'a', '1 Kings 5:14 — "And he sent them to Lebanon, ten thousand a month by courses: a month they were in Lebanon, and two months at home."'),
('1 Kings', 5, 'teens', 4, 'How many burden bearers and hewers in the mountains did Solomon conscript for the temple work?', 'Seventy thousand bearers of burdens and eighty thousand hewers in the mountains', 'Fifty thousand bearers and sixty thousand hewers', 'Forty thousand of each kind', 'A hundred thousand workers in total equally divided', 'a', '1 Kings 5:15 — "And Solomon had threescore and ten thousand that bare burdens, and fourscore thousand hewers in the mountains."'),
('1 Kings', 5, 'teens', 5, 'What special instruction did Solomon give about how the stones for the temple should be prepared?', 'They were to be prepared at the quarry so no tool of iron was heard in the house during building', 'They should be carved with cedar inlay at the site', 'Each stone should be marked with the name of a tribe', 'The Levites alone should cut and prepare the stones', 'a', '1 Kings 5:17-18 and 6:7 — "And the king commanded, and they brought great stones, costly stones...And the house, when it was in building, was built of stone made ready before it was brought thither."'),
-- Adults
('1 Kings', 5, 'adults', 1, 'What was Hiram''s reaction when he heard Solomon''s message about building the temple?', 'He rejoiced greatly and blessed the LORD for giving David a wise son over a great people', 'He asked for military alliance before sending materials', 'He consulted his own priests before agreeing', 'He demanded half of Jerusalem as payment', 'a', '1 Kings 5:7 — "And it came to pass, when Hiram heard the words of Solomon, that he rejoiced greatly, and said, Blessed be the LORD this day, which hath given unto David a wise son over this great people."'),
('1 Kings', 5, 'adults', 2, 'What condition of peace enabled Solomon to proceed with the temple that David had been denied?', 'The LORD had given Solomon rest on every side, with no adversary nor evil occurrent', 'Solomon had defeated all surrounding nations in battle', 'A treaty with Egypt had secured Israel''s borders', 'The Philistines had been removed from the land', 'a', '1 Kings 5:4 — "But now the LORD my God hath given me rest on every side, so that there is neither adversary nor evil occurrent."'),
('1 Kings', 5, 'adults', 3, 'What specific trade agreement did Solomon and Hiram formalise?', 'Hiram would supply cedar and fir timber; Solomon would supply wheat and oil annually, and there was peace between them', 'Hiram would supply timber and craftsmen; Solomon would pay in gold annually', 'A joint military alliance with shared garrisons', 'A marriage alliance sealed with Solomon''s sister', 'a', '1 Kings 5:11-12 — "And Solomon gave Hiram twenty thousand measures of wheat...and twenty measures of pure oil...And there was peace between Hiram and Solomon; and they two made a league together."'),
('1 Kings', 5, 'adults', 4, 'How did the timber reach Solomon from Lebanon?', 'Hiram made the logs into floats and brought them by sea to Joppa', 'Ox-drawn carts carried them overland through Syria', 'Levi-appointed porters carried them on their shoulders', 'Ships from Ezion-geber sailed them around to Joppa', 'a', '1 Kings 5:9 — "My servants shall bring them down from Lebanon unto the sea: and I will convey them by sea in floats unto the place that thou shalt appoint me."'),
('1 Kings', 5, 'adults', 5, 'How many overseers did Solomon appoint over the construction workers?', 'Three thousand and three hundred who ruled over the people that wrought in the work', 'One thousand overseers for each tribe', 'Seven hundred officers and three hundred deputies', 'Twelve chief overseers, one per tribe', 'a', '1 Kings 5:16 — "Beside the chief of Solomon''s officers which were over the work, three thousand and three hundred, which ruled over the people that wrought in the work."'),
('1 Kings', 5, 'adults', 6, 'What does the term "levy" (Hebrew: mas) indicate about Solomon''s labour policy?', 'It was a form of compulsory state corvée labour imposed on the Israelite population', 'It was a voluntary enlistment programme with pay', 'It referred to foreign slaves acquired in conquest', 'It was a religious duty fulfilled by each tribe in rotation', 'a', '1 Kings 5:13 — "And king Solomon raised a levy out of all Israel; and the levy was thirty thousand men," indicating forced state labour.'),
('1 Kings', 5, 'adults', 7, 'What prior relationship had existed between Hiram and David that laid the foundation for this alliance?', 'Hiram had always been a lover of David', 'Hiram and David had fought together against Philistia', 'Hiram had supplied David with materials for the palace in Jerusalem', 'Hiram had sent messengers to David after Absalom''s rebellion', 'a', '1 Kings 5:1 — "And Hiram king of Tyre sent his servants unto Solomon; for he had heard that they had anointed him king...for Hiram was ever a lover of David."'),
('1 Kings', 5, 'adults', 8, 'What theological significance does Solomon attach to the temple-building project in his message to Hiram?', 'Building a house for the name of the LORD God fulfils what the LORD promised David — that his son on the throne would build it', 'The temple would replace the tabernacle as a permanent sign of the covenant', 'The temple would be a witness to all nations of Israel''s God', 'The temple''s completion would ensure Israel''s military dominance', 'a', '1 Kings 5:5 — "And, behold, I purpose to build an house unto the name of the LORD my God, as the LORD spake unto David my father, saying, Thy son, whom I will set upon thy throne...he shall build an house unto my name."');

-- ═══ 1 Kings Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Kings', 6, 'kids', 1, 'How many years did it take Solomon to build the temple?', 'Seven years', 'Ten years', 'Three years', 'Forty years', 'a', '1 Kings 6:38 — "And in the eleventh year...was the house finished throughout all the parts thereof, and according to all the fashion of it. So was he seven years in building it."'),
('1 Kings', 6, 'kids', 2, 'What was the most holy room inside the temple called?', 'The oracle, or Most Holy Place', 'The Holy of Holies entrance', 'The inner sanctuary', 'The prayer room', 'a', '1 Kings 6:16 — "And he built twenty cubits on the sides of the house, both the floor and the walls with boards of cedar: he even built them for it within, even for the oracle, even for the most holy place."'),
('1 Kings', 6, 'kids', 3, 'What were the walls of the inside of the temple covered with?', 'Cedar wood', 'Gold', 'Marble', 'White stone', 'a', '1 Kings 6:15 — "And he built the walls of the house within with boards of cedar, both the floor of the house, and the walls of the ceiling."'),
-- Teens
('1 Kings', 6, 'teens', 1, 'What were the dimensions of the temple that Solomon built?', 'Sixty cubits long, twenty cubits wide, and thirty cubits high', 'Forty cubits long, twenty cubits wide, and twenty cubits high', 'A hundred cubits long, fifty cubits wide, and forty cubits high', 'Thirty cubits long, ten cubits wide, and fifteen cubits high', 'a', '1 Kings 6:2 — "And the house which king Solomon built for the LORD, the length thereof was threescore cubits, and the breadth thereof twenty cubits, and the height thereof thirty cubits."'),
('1 Kings', 6, 'teens', 2, 'What remarkable fact is noted about the noise level during the temple''s construction?', 'There was neither hammer nor axe nor any tool of iron heard in the house while it was being built', 'The workers sang psalms all day long', 'The people prayed in silence throughout the building', 'No animals were used in the construction', 'a', '1 Kings 6:7 — "And the house, when it was in building, was built of stone made ready before it was brought thither: so that there was neither hammer nor axe nor any tool of iron heard in the house, while it was in building."'),
('1 Kings', 6, 'teens', 3, 'What did God promise Solomon in the middle of the temple''s construction?', 'If Solomon walked in God''s statutes, God would dwell among Israel and not forsake His people', 'That the temple would stand for a thousand years', 'That no enemy would ever enter Jerusalem', 'That Solomon would reign for eighty years', 'a', '1 Kings 6:12-13 — "If thou wilt walk in my statutes, and execute my judgments...then will I perform my word with thee...And I will dwell among the children of Israel, and will not forsake my people Israel."'),
('1 Kings', 6, 'teens', 4, 'What were the two large carved figures placed inside the oracle (Most Holy Place)?', 'Two cherubims of olive tree, each ten cubits high', 'Two golden angels with outstretched wings', 'Two carved lions of cedar wood', 'Two bronze oxen facing the ark', 'a', '1 Kings 6:23 — "And within the oracle he made two cherubims of olive tree, each ten cubits high."'),
('1 Kings', 6, 'teens', 5, 'What material covered the floor of the temple''s main hall and inner oracle?', 'Boards of fir, and the floor was overlaid with gold', 'Marble tiles from Lebanon', 'Cedar planks throughout', 'Polished stone from Bashan', 'a', '1 Kings 6:15,30 — "And he built the walls of the house within with boards of cedar...And the floor of the house he overlaid with gold."'),
-- Adults
('1 Kings', 6, 'adults', 1, 'In what year and month of Solomon''s reign did he begin building the temple?', 'The fourth year, in the month of Zif, the second month', 'The third year, in the first month', 'The seventh year, in the month of Bul', 'The tenth year after his accession', 'a', '1 Kings 6:1 — "And it came to pass in the four hundred and eightieth year...in the fourth year of Solomon''s reign over Israel, in the month Zif, which is the second month, that he began to build the house of the LORD."'),
('1 Kings', 6, 'adults', 2, 'What was the porch (ulam) before the temple''s main hall, and what were its dimensions?', 'Twenty cubits long across the breadth of the house, and ten cubits deep in front of the house', 'Ten cubits wide and five cubits deep', 'Thirty cubits by fifteen cubits', 'Forty cubits long and twenty cubits wide', 'a', '1 Kings 6:3 — "And the porch before the temple of the house, twenty cubits was the length thereof, according to the breadth of the house; and ten cubits was the breadth thereof before the house."'),
('1 Kings', 6, 'adults', 3, 'What were the winding stairs in the temple used to access?', 'The middle chamber and the third storey side chambers built against the walls of the house', 'The roof of the oracle', 'The storage vaults beneath the main hall', 'The inner courts for the priests', 'a', '1 Kings 6:8 — "The door for the middle chamber was in the right side of the house: and they went up with winding stairs into the middle chamber, and out of the middle into the third."'),
('1 Kings', 6, 'adults', 4, 'How wide were the wings of each cherub, and how did they relate to the oracle''s width?', 'Each cherub had ten-cubit wingspan; together they spanned the full twenty cubits of the oracle', 'Each cherub had five-cubit wingspan covering half the oracle', 'Their wings were twelve cubits wide and overlapped', 'Their wingspan matched the height of the chamber', 'a', '1 Kings 6:24,27 — "And five cubits was the one wing of the cherub, and five cubits the other wing...and the wings of the cherubims were twenty cubits."'),
('1 Kings', 6, 'adults', 5, 'What carved decorations adorned the cedar walls throughout the main hall of the temple?', 'Knops, open flowers, cherubims, and palm trees carved in cedar', 'Only the menorah and table of shewbread images', 'Scenes from Israel''s history in relief', 'Geometric patterns and tribal emblems', 'a', '1 Kings 6:29 — "And he carved all the walls of the house round about with carved figures of cherubims and palm trees and open flowers, within and without."'),
('1 Kings', 6, 'adults', 6, 'What were the doors of the oracle and the main hall made of, and what was carved on them?', 'The oracle doors of olive tree with cherubims, palm trees, and flowers overlaid with gold; the main hall doors of fir tree', 'Both sets of doors were of cedar overlaid with pure gold', 'The oracle doors were of acacia wood; the hall doors of cedar', 'All doors were of bronze, with silver overlays for the carvings', 'a', '1 Kings 6:31-34 — "And for the entering of the oracle he made doors of olive tree...And for the entering of the temple he made doors of fir tree."'),
('1 Kings', 6, 'adults', 7, 'What does the phrase "in the four hundred and eightieth year after the children of Israel were come out of the land of Egypt" situate chronologically?', 'It places the temple''s foundation in a pivotal redemptive timeline connecting Exodus to the Solomonic era', 'It corrects an error in the book of Judges', 'It proves Solomon''s ancestry from the Exodus generation', 'It marks the boundary between the period of the judges and the monarchy', 'a', '1 Kings 6:1 — "And it came to pass in the four hundred and eightieth year after the children of Israel were come out of the land of Egypt...that he began to build the house of the LORD."'),
('1 Kings', 6, 'adults', 8, 'In what year and month was the temple completed according to the closing verse of chapter 6?', 'The eleventh year in the month of Bul, the eighth month', 'The tenth year in the month of Zif', 'The fourteenth year in the first month', 'The seventh year in the month of Nisan', 'a', '1 Kings 6:38 — "And in the eleventh year, in the month Bul, which is the eighth month, was the house finished."');

-- ═══ 1 Kings Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Kings', 7, 'kids', 1, 'What were the names of the two large bronze pillars Solomon placed at the temple porch?', 'Jachin and Boaz', 'Urim and Thummim', 'Strength and Beauty', 'Cedar and Oak', 'a', '1 Kings 7:21 — "And he set up the pillars in the porch of the temple...and he called the name thereof Jachin: and he called the name of the left pillar Boaz."'),
('1 Kings', 7, 'kids', 2, 'How many years did Solomon spend building his own palace?', 'Thirteen years', 'Seven years', 'Ten years', 'Twenty years', 'a', '1 Kings 7:1 — "But Solomon was building his own house thirteen years, and he finished all his house."'),
('1 Kings', 7, 'kids', 3, 'What was the name of the large round bronze basin made for the temple?', 'A molten sea', 'The brass pool', 'The great laver', 'The bronze fountain', 'a', '1 Kings 7:23 — "And he made a molten sea, ten cubits from the one brim to the other."'),
-- Teens
('1 Kings', 7, 'teens', 1, 'Who was Hiram the craftsman, and who sent him to Solomon?', 'A widow''s son of the tribe of Naphtali, a worker in brass sent by Hiram king of Tyre', 'A Levite appointed by Zadok', 'An Egyptian craftsman hired by Solomon', 'A Phoenician architect from Byblos', 'a', '1 Kings 7:13-14 — "And king Solomon sent and fetched Hiram out of Tyre. He was a widow''s son of the tribe of Naphtali, and his father was a man of Tyre, a worker in brass."'),
('1 Kings', 7, 'teens', 2, 'How tall were the two bronze pillars, and what topped them?', 'Eighteen cubits high each, with chapiters of molten brass five cubits tall', 'Twenty cubits high with carved cedar tops', 'Thirty cubits high with golden capitals', 'Twelve cubits high with lily-shaped crowns', 'a', '1 Kings 7:15-16 — "For he cast two pillars of brass, of eighteen cubits high apiece...and he made two chapiters of molten brass, to set upon the tops of the pillars: the height of the one chapiter was five cubits."'),
('1 Kings', 7, 'teens', 3, 'How many oxen did the molten sea rest upon, and how were they arranged?', 'Twelve oxen — three facing each cardinal direction', 'Four oxen, one at each corner', 'Eight oxen in two rows', 'Six oxen arranged in a circle', 'a', '1 Kings 7:25 — "It stood upon twelve oxen, three looking toward the north, and three looking toward the west, and three looking toward the south, and three looking toward the east."'),
('1 Kings', 7, 'teens', 4, 'How many lavers did Solomon place in the temple court, and what were they used for?', 'Ten lavers to wash in, used for washing burnt offerings', 'Twelve lavers for purification rites', 'Seven lavers symbolizing completeness', 'Four lavers at the corners of the court', 'a', '1 Kings 7:38-39 — "Then made he ten lavers of brass: one laver contained forty baths...and he put five on the right side of the house, and five on the left side."'),
('1 Kings', 7, 'teens', 5, 'What building in Solomon''s palace complex was named after a notable tree used in its construction?', 'The house of the forest of Lebanon', 'The cedar hall of justice', 'The olive-wood throne room', 'The fir-tree audience chamber', 'a', '1 Kings 7:2 — "He built also the house of the forest of Lebanon; the length thereof was an hundred cubits, and the breadth thereof fifty cubits."'),
-- Adults
('1 Kings', 7, 'adults', 1, 'What was the Hall of Pillars and what were its dimensions?', 'A porch of pillars fifty cubits long and thirty cubits broad with a porch of judgment before it', 'A colonnade forty cubits by twenty cubits for public audiences', 'A seventy-cubit hall used for storing weapons', 'A ninety-cubit gallery connecting the palace to the temple', 'a', '1 Kings 7:6 — "And he made a porch of pillars; the length thereof was fifty cubits, and the breadth thereof thirty cubits: and the porch was before them."'),
('1 Kings', 7, 'adults', 2, 'What were the bases (mekonoth) of the lavers made of, and what decorated them?', 'Brass bases with lions, oxen, cherubims, wreaths of work, and wheels of brass', 'Cedar frames inlaid with gold lions', 'Stone pedestals carved with floral designs', 'Iron stands overlaid with bronze plates', 'a', '1 Kings 7:29 — "And on the borders...were lions, oxen, and cherubims: and upon the bases so...a work of base work."'),
('1 Kings', 7, 'adults', 3, 'What was the capacity of the molten sea in terms of baths?', 'It contained two thousand baths', 'It held five hundred baths', 'Its capacity was three thousand baths', 'It measured one thousand baths', 'a', '1 Kings 7:26 — "And it was an hand breadth thick, and the brim thereof was wrought like the brim of a cup, with flowers of lilies: it contained two thousand baths."'),
('1 Kings', 7, 'adults', 4, 'What was the primary purpose of the molten sea according to chapter 7?', 'For the priests to wash in', 'For purifying the burnt offerings', 'For storing water in case of siege', 'For ceremonial immersion of the altar', 'a', '1 Kings 7:39 — "And he put five bases on the right side of the house, and five on the left side...and the sea was set on the right side of the house eastward over against the south." (2 Chronicles 4:6 clarifies the sea was for the priests to wash in.)'),
('1 Kings', 7, 'adults', 5, 'What items in the temple were made of pure gold rather than brass?', 'The altar, table of shewbread, candlesticks, flowers, lamps, tongs, bowls, spoons, censers, hinges — all of pure gold', 'Only the ark overlay and the cherubim', 'Only the candlesticks and the altar of incense', 'The pillars Jachin and Boaz alone', 'a', '1 Kings 7:48-50 — "And Solomon made all the vessels...the altar of gold, and the table of gold, whereupon the shewbread was...And the candlesticks of pure gold...and all the vessels of the house of the LORD."'),
('1 Kings', 7, 'adults', 6, 'What summary statement closes the account of all the temple furniture Hiram made for Solomon?', 'Hiram made an end of doing all the work he made for king Solomon for the house of the LORD', 'The work was declared very good and blessed by the priests', 'Solomon accepted the work and presented Hiram with gifts', 'The people assembled to see the completed furnishings', 'a', '1 Kings 7:40 — "And Hiram made the lavers, and the shovels, and the basons. So Hiram made an end of doing all the work that he made king Solomon for the house of the LORD."'),
('1 Kings', 7, 'adults', 7, 'In what plain did Solomon have all the brass items cast, and why was that location chosen?', 'In the plain of Jordan between Succoth and Zarthan, in the clay ground', 'In the valley of Hinnom outside Jerusalem', 'Near the copper mines of the Arabah', 'In the wilderness of Sinai near the Tabernacle''s former site', 'a', '1 Kings 7:46 — "In the plain of Jordan did the king cast them, in the clay ground between Succoth and Zarthan."'),
('1 Kings', 7, 'adults', 8, 'What does the phrase "Solomon left all the vessels unweighed" indicate about the quantity of brass used?', 'The brass was exceeding much; the weight could not be found out', 'The priests deemed weighing unnecessary after the dedication', 'The craftsmen lost count during production', 'Only approximate totals were kept in the royal records', 'a', '1 Kings 7:47 — "And Solomon left all the vessels unweighed, because they were exceeding many: neither was the weight of the brass found out."');

-- ═══ 1 Kings Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Kings', 8, 'kids', 1, 'What holy object was brought into the temple when it was dedicated?', 'The ark of the covenant of the LORD', 'The golden candlestick', 'The bronze altar', 'The tabernacle of Moses', 'a', '1 Kings 8:1 — "Then Solomon assembled the elders of Israel...to bring up the ark of the covenant of the LORD out of the city of David."'),
('1 Kings', 8, 'kids', 2, 'What filled the temple when the ark was placed inside?', 'A cloud — the glory of the LORD', 'A great fire', 'Heavenly music', 'A sweet fragrance', 'a', '1 Kings 8:10-11 — "And it came to pass...that the cloud filled the house of the LORD...for the glory of the LORD had filled the house of the LORD."'),
('1 Kings', 8, 'kids', 3, 'What were inside the ark of the covenant when it was brought to the temple?', 'The two tables of stone which Moses put there at Horeb', 'The rod of Aaron and a pot of manna', 'The Ten Commandments and the book of the law', 'Golden bells and pomegranates', 'a', '1 Kings 8:9 — "There was nothing in the ark save the two tables of stone, which Moses put there at Horeb."'),
-- Teens
('1 Kings', 8, 'teens', 1, 'What was Solomon''s declaration about God''s dwelling place that showed humility?', 'The heaven and heaven of heavens cannot contain thee; how much less this house that I have builded?', 'Let the temple be thy dwelling forever', 'God is too great for any building to contain him', 'This house is too small for the LORD', 'a', '1 Kings 8:27 — "But will God indeed dwell on the earth? behold, the heaven and heaven of heavens cannot contain thee; how much less this house that I have builded?"'),
('1 Kings', 8, 'teens', 2, 'In his prayer, what did Solomon ask God to do when Israel was defeated because of sin but then repented?', 'Hear their prayer, forgive, and bring them again to the land God gave their fathers', 'Send a sign from heaven to confirm His forgiveness', 'Raise up a prophet to guide the repentant people', 'Remove the enemy nations from their borders', 'a', '1 Kings 8:34 — "Then hear thou in heaven, and forgive the sin of thy people Israel, and bring them again unto the land which thou gavest unto their fathers."'),
('1 Kings', 8, 'teens', 3, 'What offering did Solomon make at the temple dedication, and how large was it?', 'Twenty-two thousand oxen and an hundred and twenty thousand sheep', 'A thousand burnt offerings', 'Seven days of daily sacrifices', 'Three thousand oxen and sixty thousand sheep', 'a', '1 Kings 8:63 — "And Solomon offered a sacrifice of peace offerings, which he offered unto the LORD, two and twenty thousand oxen, and an hundred and twenty thousand sheep."'),
('1 Kings', 8, 'teens', 4, 'How long did the feast of dedication last?', 'Fourteen days — seven days and then another seven days', 'Seven days only', 'One month of daily ceremonies', 'Forty days to mirror Moses on Sinai', 'a', '1 Kings 8:65 — "And at that time Solomon held a feast, and all Israel with him...seven days and seven days, even fourteen days."'),
('1 Kings', 8, 'teens', 5, 'What did Solomon ask God to grant to foreigners who would come from far away and pray toward the temple?', 'Do all that the stranger calleth to thee for, that all people may know God''s name and fear Him', 'Give them double the blessing of Israel', 'Let them become part of Israel', 'Hear their prayer only if they convert to Israel''s faith', 'a', '1 Kings 8:43 — "Hear thou in heaven thy dwelling place, and do according to all that the stranger calleth to thee for: that all people of the earth may know thy name."'),
-- Adults
('1 Kings', 8, 'adults', 1, 'In what month and during what feast was the ark brought to the temple?', 'The feast of the seventh month — the feast of tabernacles (Ethanim)', 'The Passover feast in the first month', 'The feast of weeks in the third month', 'The new year feast at the start of Bul', 'a', '1 Kings 8:2 — "And all the men of Israel assembled themselves unto king Solomon at the feast in the month Ethanim, which is the seventh month."'),
('1 Kings', 8, 'adults', 2, 'What was the theological significance of the staves (poles) being visible at the holy place?', 'They were a visible witness that the ark — God''s presence — was permanently installed; they are there unto this day', 'They indicated the ark was ready to be transported again', 'They symbolised the two tablets of the covenant', 'They were a priestly reminder of the wilderness journey', 'a', '1 Kings 8:8 — "And the staves were so long, that the ends of the staves were seen out in the holy place before the oracle, and they were not seen without: and there they are unto this day."'),
('1 Kings', 8, 'adults', 3, 'What did Solomon say God had fulfilled by the temple dedication that had been promised to David?', 'God had fulfilled with His hand what He spoke with His mouth — the promise to David His servant', 'The covenant land from Egypt to Euphrates was fully possessed', 'Peace from all enemies had been perfectly achieved', 'The number of Israel was as God had promised to Abraham', 'a', '1 Kings 8:24 — "Who hast kept with thy servant David my father that thou promisedst him: thou spakest also with thy mouth, and hast fulfilled it with thine hand."'),
('1 Kings', 8, 'adults', 4, 'What seven petitions does Solomon''s prayer (vv. 31-53) address?', 'Oath disputes, defeat in battle, drought, famine/plague, foreign prayer, war, and captivity', 'Forgiveness, healing, rain, harvest, war, plague, and peace', 'Individual sin, national sin, famine, drought, enemies, foreigners, and warfare', 'Prayer in crisis, mercy for the repentant, justice for the wicked, healing for the sick, blessing for the righteous, peace for the land, and return from exile', 'a', '1 Kings 8:31-53 — Solomon''s dedicatory prayer contains seven petitions covering oath swearing, military defeat, drought, famine/pestilence, foreigner''s prayer, war, and exile/captivity.'),
('1 Kings', 8, 'adults', 5, 'What Exodus-rooted theology does Solomon invoke at the close of his prayer to ground his appeal?', 'God separated Israel from all people of the earth to be His inheritance, as He said through Moses His servant', 'God brought Israel out of Egypt with a mighty hand and a stretched-out arm', 'God gave Israel the law at Sinai as a covenant of mercy', 'God chose Israel because of Abraham''s faith, not their own merit', 'a', '1 Kings 8:53 — "For thou didst separate them from among all the people of the earth, to be thine inheritance, as thou spakest by the hand of Moses thy servant."'),
('1 Kings', 8, 'adults', 6, 'What blessing did Solomon pronounce over Israel after his prayer?', 'Blessed be the LORD that hath given rest unto his people Israel according to all that he promised; not one word of all his good promise hath failed', 'May the LORD prosper you in all your ways', 'The LORD your God will be with you as He was with our fathers', 'Go and serve the LORD your God with all your heart and all your soul', 'a', '1 Kings 8:56 — "Blessed be the LORD, that hath given rest unto his people Israel, according to all that he promised: there hath not failed one word of all his good promise."'),
('1 Kings', 8, 'adults', 7, 'What final exhortation did Solomon give to Israel after the blessing?', 'Let your heart be perfect with the LORD our God, to walk in his statutes and keep his commandments as at this day', 'Return to your tents and rejoice in the LORD', 'Fear the LORD and serve Him in truth and sincerity', 'Remember what God did for your fathers in Egypt', 'a', '1 Kings 8:61 — "Let your heart therefore be perfect with the LORD our God, to walk in his statutes, and to keep his commandments, as at this day."'),
('1 Kings', 8, 'adults', 8, 'What happens to the priests when they cannot stand to minister because of the cloud, and what does this signify?', 'The overwhelming presence of God''s glory filling the house made priestly service impossible, showing God''s actual indwelling', 'The priests were temporarily blinded by a heavenly light', 'The weight of the cloud collapsed part of the structure', 'The priests fell prostrate in worship and could not stand', 'a', '1 Kings 8:11 — "So that the priests could not stand to minister because of the cloud: for the glory of the LORD had filled the house of the LORD."');

-- ═══ 1 Kings Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Kings', 9, 'kids', 1, 'Did God appear to Solomon again after the temple was built?', 'Yes, a second time, as He had appeared at Gibeon', 'No, God never appeared to Solomon again', 'Yes, many more times throughout his reign', 'No, only the prophets heard from God after that', 'a', '1 Kings 9:2 — "That the LORD appeared to Solomon the second time, as he had appeared unto him at Gibeon."'),
('1 Kings', 9, 'kids', 2, 'What did God promise to do to the temple if Israel turned away and worshipped other gods?', 'Cast out Israel and the house shall be a proverb and a byword among all people', 'Shut the temple doors forever', 'Remove the ark of the covenant', 'Burn it with heavenly fire', 'a', '1 Kings 9:7 — "Then will I cut off Israel out of the land which I have given them; and this house, which I have hallowed for my name, will I cast out of my sight; and Israel shall be a proverb and a byword among all people."'),
('1 Kings', 9, 'kids', 3, 'What did Solomon give Hiram king of Tyre in return for all his help?', 'Twenty cities in the land of Galilee', 'Silver equal to the wood he sent', 'A yearly tribute of gold', 'Hiram''s own son a place in the palace', 'a', '1 Kings 9:11 — "Solomon gave Hiram twenty cities in the land of Galilee."'),
-- Teens
('1 Kings', 9, 'teens', 1, 'What conditional warning did God give Solomon regarding the temple and the kingdom?', 'If Israel forsook God''s commandments and served other gods, He would cut off Israel and the temple would be a heap of ruins and a byword', 'If Solomon built altars to foreign gods he alone would be punished', 'The temple would stand only as long as the Levites served faithfully', 'God would withhold rain until the people returned to the temple', 'a', '1 Kings 9:6-7 — "But if ye shall at all turn from following me...then will I cut off Israel out of the land...and this house, which I have hallowed for my name, will I cast out of my sight."'),
('1 Kings', 9, 'teens', 2, 'What was Hiram''s reaction when he saw the twenty cities Solomon gave him?', 'He was displeased and called them Cabul — a name meaning "good for nothing"', 'He was greatly pleased and thanked Solomon', 'He accepted them without comment', 'He sent them back and asked for gold instead', 'a', '1 Kings 9:12-13 — "And Hiram came out from Tyre to see the cities which Solomon had given him; and they pleased him not. And he called them the land of Cabul unto this day."'),
('1 Kings', 9, 'teens', 3, 'What did Solomon do with the remnant of non-Israelite peoples still living in Canaan?', 'He put them under tribute of bond service; he did not make the children of Israel servants', 'He expelled them from the land completely', 'He gave them equal status with the Israelites', 'He put them all to the sword', 'a', '1 Kings 9:20-22 — "And all the people that were left of the Amorites, Hittites...which were not of the children of Israel...upon those did Solomon levy a tribute of bondservice unto this day. But of the children of Israel did Solomon make no bondmen."'),
('1 Kings', 9, 'teens', 4, 'What fleet did Solomon build at Ezion-geber and what was its significance?', 'A navy of ships on the Red Sea shore in Edom, staffed with Hiram''s shipmen alongside Solomon''s men', 'A river fleet on the Jordan for trade with the north', 'A Mediterranean fleet based at Joppa', 'A war fleet to guard the Euphrates border', 'a', '1 Kings 9:26-27 — "And king Solomon made a navy of ships in Ezion-geber...on the shore of the Red sea...And Hiram sent in the navy his servants, shipmen that had knowledge of the sea, with the servants of Solomon."'),
('1 Kings', 9, 'teens', 5, 'How much gold did the fleet bring back to Solomon from Ophir?', 'Four hundred and twenty talents of gold', 'A thousand talents of gold', 'Three hundred talents of gold', 'Six hundred and sixty-six talents', 'a', '1 Kings 9:28 — "And they came to Ophir, and fetched from thence gold, four hundred and twenty talents, and brought it to king Solomon."'),
-- Adults
('1 Kings', 9, 'adults', 1, 'What two-part divine affirmation did God give Solomon at the beginning of chapter 9?', 'God had heard Solomon''s prayer, had hallowed the temple as His name''s dwelling forever, and His eyes and heart would be there perpetually', 'God confirmed the Davidic covenant without conditions', 'God promised Solomon military victory over all nations', 'God extended Solomon''s reign for an additional forty years', 'a', '1 Kings 9:3 — "And the LORD said unto him, I have heard thy prayer and thy supplication...I have hallowed this house...to put my name there for ever; and mine eyes and mine heart shall be there perpetually."'),
('1 Kings', 9, 'adults', 2, 'What threefold conditional promise did God make to Solomon personally in this second appearance?', 'If Solomon walked before God as David had done, in integrity and uprightness, keeping His statutes, God would establish the throne of Israel forever', 'God would make Solomon the wisest man of all time if he kept the law', 'God promised long life, riches, and victory to Solomon personally', 'God pledged ten additional tribes to Solomon''s successors', 'a', '1 Kings 9:4-5 — "And if thou wilt walk before me, as David thy father walked...then I will establish the throne of thy kingdom upon Israel for ever, as I promised to David."'),
('1 Kings', 9, 'adults', 3, 'What stunning reversal does the name "Cabul" represent in the context of Solomon''s alliance with Hiram?', 'A diplomatic embarrassment — Solomon''s payment in land failed to satisfy Hiram, undermining the friendship', 'A legal boundary dispute that led to war', 'A sign that Solomon had no more land to give', 'A deliberate insult from Solomon to Hiram', 'a', '1 Kings 9:13 — "And he said, What cities are these which thou hast given me, my brother? And he called them the land of Cabul unto this day."'),
('1 Kings', 9, 'adults', 4, 'How many workers did Solomon assign to oversee the labour on his building projects, and how were they categorised?', 'Three thousand three hundred chief officers who bore rule over the people — distinguished from the 550 who ruled over the chief work', 'Twelve governors, one per tribe', 'Seventy elders appointed as overseers', 'Five hundred officials with the high priest as chief overseer', 'a', '1 Kings 9:23 — "These were the chief of the officers that were over Solomon''s work, five hundred and fifty, which bare rule over the people that wrought in the work."'),
('1 Kings', 9, 'adults', 5, 'What was the theological purpose of the three annual occasions when Solomon offered burnt offerings at the temple?', 'He offered on the three feasts — Passover, Pentecost (Weeks), and Tabernacles — the appointed sacred calendar of Israel', 'He offered monthly to mark each new moon', 'He offered weekly every Sabbath before the ark', 'He offered only when returning from military campaigns', 'a', '1 Kings 9:25 — "And three times in a year did Solomon offer burnt offerings and peace offerings upon the altar which he built unto the LORD...on the three feasts."'),
('1 Kings', 9, 'adults', 6, 'What building projects beyond the temple and palace does chapter 9 record Solomon completing?', 'The Millo, the wall of Jerusalem, Hazor, Megiddo, Gezer, Lower Beth-horon, Baalath, and Tadmor', 'Only the palace and the temple complex were listed', 'Storehouses and granaries in every tribe''s territory', 'Forts along the Egyptian border and the coast', 'a', '1 Kings 9:15-18 — "And this is the reason of the levy...to build the house of the LORD, and his own house, and Millo, and the wall of Jerusalem, and Hazor, and Megiddo, and Gezer."'),
('1 Kings', 9, 'adults', 7, 'Why was the city of Gezer included in Solomon''s building programme?', 'Pharaoh had taken it, burned it, killed its Canaanite inhabitants, and given it as a dowry to Solomon''s Egyptian wife', 'Solomon conquered it himself in a military campaign', 'It was purchased from the Canaanites for silver', 'It was given to Solomon by Hiram of Tyre as part of their treaty', 'a', '1 Kings 9:16 — "For Pharaoh king of Egypt had gone up, and taken Gezer, and burnt it with fire, and slain the Canaanites that dwelt in the city, and given it for a present unto his daughter, Solomon''s wife."'),
('1 Kings', 9, 'adults', 8, 'What does Solomon''s building of Tadmor in the wilderness and store cities in Hamath suggest about his reign''s geographic reach?', 'His empire and influence extended well beyond Canaan into northern Syria and the desert trade routes', 'He was merely fortifying borders for defence', 'These were religious centres for Israelite diaspora communities', 'They were built to house the excess labour force from the levy', 'a', '1 Kings 9:18-19 — "And Baalath, and Tadmor in the wilderness, in the land...And all the cities of store that Solomon had, and cities for his chariots, and cities for his horsemen."');

-- ═══ 1 Kings Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Kings', 10, 'kids', 1, 'Who came from far away to test Solomon''s wisdom with hard questions?', 'The queen of Sheba', 'The king of Egypt', 'The queen of Ethiopia', 'The princess of Tyre', 'a', '1 Kings 10:1 — "And when the queen of Sheba heard of the fame of Solomon concerning the name of the LORD, she came to prove him with hard questions."'),
('1 Kings', 10, 'kids', 2, 'What did the queen of Sheba say when she saw all of Solomon''s wisdom and riches?', 'The half was not told me; thy wisdom and prosperity exceedeth the fame I heard', 'Solomon is truly the greatest king in the world', 'I have never seen anything like this in all my travels', 'Blessed are thy men who stand before thee and hear thy wisdom', 'a', '1 Kings 10:7 — "Howbeit I believed not the words, until I came, and mine eyes had seen it: and, behold, the half was not told me."'),
('1 Kings', 10, 'kids', 3, 'What special throne did Solomon make?', 'A great throne of ivory overlaid with the best gold', 'A cedar throne with gold cushions', 'A throne of pure gold with twelve pillars', 'A bronze throne set with precious stones', 'a', '1 Kings 10:18 — "Moreover the king made a great throne of ivory, and overlaid it with the best gold."'),
-- Teens
('1 Kings', 10, 'teens', 1, 'What did the queen of Sheba bring Solomon when she visited?', 'Spices, very much gold, and precious stones', 'Silks and fine linen from the east', 'Horses and chariots as tribute', 'Ivory and rare birds', 'a', '1 Kings 10:2 — "And she came to Jerusalem with a very great train, with camels that bare spices, and very much gold, and precious stones."'),
('1 Kings', 10, 'teens', 2, 'What blessing did the queen of Sheba pronounce about the God of Israel?', 'Blessed be the LORD thy God, which delighted in thee, to set thee on the throne of Israel', 'Your God is the true God above all gods', 'The LORD has given thee all wisdom and riches', 'Blessed are the people whose God is the LORD', 'a', '1 Kings 10:9 — "Blessed be the LORD thy God, which delighted in thee, to set thee on the throne of Israel: because the LORD loved Israel for ever, therefore made he thee king."'),
('1 Kings', 10, 'teens', 3, 'How much gold did Solomon receive each year?', 'Six hundred threescore and six talents of gold', 'A thousand talents annually', 'Five hundred talents from taxes and five hundred from trade', 'Two thousand talents from the queen of Sheba alone', 'a', '1 Kings 10:14 — "Now the weight of gold that came to Solomon in one year was six hundred threescore and six talents of gold."'),
('1 Kings', 10, 'teens', 4, 'What was unique about the steps of Solomon''s ivory throne?', 'Six steps led to it with twelve lions, two on each side of the six steps', 'It had seven steps representing the days of creation', 'The steps were made of solid gold', 'It was raised on a platform of carved cedar', 'a', '1 Kings 10:19-20 — "The throne had six steps, and the top of the throne was round behind: and there were stays on either side...And twelve lions stood there on the one side and on the other."'),
('1 Kings', 10, 'teens', 5, 'What was Solomon''s trading fleet called and where did it sail?', 'The navy of Tharshish bringing gold, silver, ivory, apes, and peacocks every three years', 'The fleet of Ophir sailing monthly to Arabia', 'The ships of Tarshish carrying cedar and fir to Egypt', 'The eastern fleet trading silk and spices with India', 'a', '1 Kings 10:22 — "For the king had at sea a navy of Tharshish with the navy of Hiram: once in three years came the navy of Tharshish, bringing gold, and silver, ivory, and apes, and peacocks."'),
-- Adults
('1 Kings', 10, 'adults', 1, 'What does the text say the queen of Sheba''s heart was like after Solomon answered all her questions?', 'There was no more spirit in her', 'She was filled with wonder and joy', 'She was moved to tears', 'She sat speechless for a long while', 'a', '1 Kings 10:5 — "And when the queen of Sheba had seen all Solomon''s wisdom, and the house that he had built...there was no more spirit in her."'),
('1 Kings', 10, 'adults', 2, 'How many targets of beaten gold did Solomon make, and how much gold went into each?', 'Two hundred targets of six hundred shekels of gold each', 'A hundred targets of a thousand shekels each', 'Three hundred shields of three hundred shekels each', 'Five hundred targets of five hundred shekels each', 'a', '1 Kings 10:16 — "And king Solomon made two hundred targets of beaten gold: six hundred shekels of gold went to one target."'),
('1 Kings', 10, 'adults', 3, 'Where were the gold targets and shields stored that Solomon had made?', 'In the house of the forest of Lebanon', 'In the treasury of the temple', 'In Solomon''s palace armoury', 'Under the throne room floor', 'a', '1 Kings 10:17 — "And he made three hundred shields of beaten gold; three pound of gold went to one shield: and the king put them in the house of the forest of Lebanon."'),
('1 Kings', 10, 'adults', 4, 'What material was used for all Solomon''s drinking vessels, and what became of silver?', 'All King Solomon''s drinking vessels were of gold; silver was nothing accounted of in the days of Solomon', 'Gold and silver vessels were used equally', 'Only the temple vessels were gold; palace vessels were silver', 'Gold was reserved for the temple while silver served the palace', 'a', '1 Kings 10:21 — "And all king Solomon''s drinking vessels were of gold...none were of silver: it was nothing accounted of in the days of Solomon."'),
('1 Kings', 10, 'adults', 5, 'How many chariots and horsemen did Solomon accumulate, and where did he house them?', 'One thousand four hundred chariots and twelve thousand horsemen in chariot cities and with the king in Jerusalem', 'Two thousand chariots in forty stall cities', 'A thousand chariots and ten thousand horsemen stationed at Megiddo only', 'Three thousand chariots distributed among the twelve tribes', 'a', '1 Kings 10:26 — "And Solomon gathered together chariots and horsemen: and he had a thousand and four hundred chariots, and twelve thousand horsemen...in the cities for chariots, and with the king at Jerusalem."'),
('1 Kings', 10, 'adults', 6, 'What does the statement about Solomon''s wealth echo regarding Deuteronomy''s warnings to the king?', 'It foreshadows the kingly violations Moses warned against — multiplying horses, gold, and wives — the very sins of chapter 11', 'It proves Solomon fully obeyed Deuteronomy 17', 'It shows God blessed Solomon beyond any previous king without conditions', 'It demonstrates that wealth is always a sign of divine favour', 'a', '1 Kings 10:14-29 — Solomon''s multiplication of gold, chariots and horses directly echoes Deuteronomy 17:16-17''s prohibitions against the king multiplying horses, gold, and wives.'),
('1 Kings', 10, 'adults', 7, 'What trade route controlled by Solomon made him the middleman for horse and chariot commerce?', 'He imported horses from Egypt and Kue, and kings of the Hittites and Syria bought through Solomon''s merchants', 'He monopolised the spice trade from Arabia', 'He controlled the copper trade from the Arabah', 'He dominated the grain trade from Egypt to Mesopotamia', 'a', '1 Kings 10:28-29 — "And Solomon had horses brought out of Egypt, and linen yarn...and so for all the kings of the Hittites, and for the kings of Syria, did they bring them out by their means."'),
('1 Kings', 10, 'adults', 8, 'What superlative statement summarises Solomon''s stature among the kings of his era?', 'King Solomon exceeded all the kings of the earth for riches and for wisdom', 'No king since David had such military power', 'Israel was the mightiest empire in the world', 'Solomon''s temple made Jerusalem the centre of all worship', 'a', '1 Kings 10:23 — "So king Solomon exceeded all the kings of the earth for riches and for wisdom."');

-- ═══ 1 Kings Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Kings', 11, 'kids', 1, 'What did Solomon do that made God angry?', 'He loved many foreign women and they turned his heart after other gods', 'He stopped offering sacrifices at the temple', 'He raised taxes on the poor', 'He refused to listen to the prophets', 'a', '1 Kings 11:4 — "For it came to pass, when Solomon was old, that his wives turned away his heart after other gods."'),
('1 Kings', 11, 'kids', 2, 'What did God say He would do to Solomon''s kingdom because of his sin?', 'Rend the kingdom from Solomon and give it to his servant', 'Destroy the temple he had built', 'Remove all Solomon''s riches', 'Send enemies to defeat Israel', 'a', '1 Kings 11:11 — "Wherefore the LORD said unto Solomon...I will surely rend the kingdom from thee, and will give it to thy servant."'),
('1 Kings', 11, 'kids', 3, 'Which tribe would remain with Solomon''s son because of God''s love for David and Jerusalem?', 'One tribe', 'Two tribes', 'Five tribes', 'All the tribes', 'a', '1 Kings 11:13 — "Howbeit I will not rend away all the kingdom; but will give one tribe to thy son for David my servant''s sake."'),
-- Teens
('1 Kings', 11, 'teens', 1, 'How many wives and concubines did Solomon have?', 'Seven hundred wives, princesses, and three hundred concubines', 'A hundred wives and fifty concubines', 'Three hundred wives and seven hundred concubines', 'Five hundred wives in all', 'a', '1 Kings 11:3 — "And he had seven hundred wives, princesses, and three hundred concubines: and his wives turned away his heart."'),
('1 Kings', 11, 'teens', 2, 'What false gods did Solomon follow because of his foreign wives?', 'Ashtoreth of the Zidonians and Milcom of the Ammonites', 'Baal and Asherah', 'Chemosh and Molech', 'Dagon and Rimmon', 'a', '1 Kings 11:5 — "For Solomon went after Ashtoreth the goddess of the Zidonians, and after Milcom the abomination of the Ammonites."'),
('1 Kings', 11, 'teens', 3, 'Who was the prophet that delivered God''s message to Jeroboam about the torn kingdom?', 'Ahijah the Shilonite', 'Nathan the prophet', 'Shemaiah of Judah', 'Gad the seer', 'a', '1 Kings 11:29 — "And it came to pass at that time when Jeroboam went out of Jerusalem, that the prophet Ahijah the Shilonite found him in the way."'),
('1 Kings', 11, 'teens', 4, 'What did the prophet Ahijah do with his new garment to deliver his message to Jeroboam?', 'He tore it into twelve pieces and told Jeroboam to take ten', 'He wrapped Jeroboam in it as a sign of kingship', 'He burned it before Jeroboam as a sign of God''s judgment', 'He folded it and placed it on Jeroboam''s head', 'a', '1 Kings 11:30-31 — "And Ahijah caught the new garment that was on him, and rent it in twelve pieces: And he said to Jeroboam, Take thee ten pieces."'),
('1 Kings', 11, 'teens', 5, 'What three adversaries did God raise up against Solomon during his reign?', 'Hadad the Edomite, Rezon son of Eliadah, and Jeroboam son of Nebat', 'Hiram of Tyre, the queen of Sheba, and a Philistine king', 'Pharaoh of Egypt, the king of Moab, and Abimelech', 'A Philistine general, a Syrian commander, and an Ammonite prince', 'a', '1 Kings 11:14,23,26 — "And the LORD stirred up an adversary unto Solomon, Hadad the Edomite...And God stirred him up another adversary, Rezon...And Jeroboam...lifted up his hand against the king."'),
-- Adults
('1 Kings', 11, 'adults', 1, 'What was the precise commandment regarding foreign women that God had given Israel, and how is it cited in chapter 11?', 'God had said Israel shall not go in to the nations, neither shall they come in unto Israel, for they will turn away your heart after their gods', 'God had forbidden marriage outside the twelve tribes entirely', 'God had permitted marriage to proselytes but not to worshippers of idols', 'God had warned Solomon specifically in the dream at Gibeon against foreign marriage', 'a', '1 Kings 11:2 — "Of the nations concerning which the LORD said unto the children of Israel, Ye shall not go in to them, neither shall they come in unto you: for surely they will turn away your heart after their gods."'),
('1 Kings', 11, 'adults', 2, 'On what mountain did Solomon build high places for the abominations of Moab and Ammon?', 'The hill that is before Jerusalem', 'Mount Carmel', 'The Mount of Olives', 'Mount Zion', 'a', '1 Kings 11:7 — "Then did Solomon build an high place for Chemosh, the abomination of Moab, in the hill that is before Jerusalem, and for Molech, the abomination of the children of Ammon."'),
('1 Kings', 11, 'adults', 3, 'Why did God withhold the kingdom division from Solomon''s own lifetime rather than tearing it in Solomon''s day?', 'For David his father''s sake, God deferred the division to Solomon''s son''s time', 'Because Solomon repented in his old age', 'Because the temple still needed Solomon to maintain it', 'Because no suitable replacement ruler had yet been found', 'a', '1 Kings 11:12 — "Notwithstanding in thy days I will not do it for David thy father''s sake: but I will rend it out of the hand of thy son."'),
('1 Kings', 11, 'adults', 4, 'What was the background of Hadad the Edomite, and why was he a persistent thorn for Solomon?', 'Hadad had escaped Joab''s massacre in Edom as a child, fled to Egypt, married Pharaoh''s sister-in-law, and returned to Edom to be adversary to Israel', 'Hadad was a Philistine king who raided Israel''s borders', 'Hadad was a former Israelite officer who defected to Edom', 'Hadad was a nephew of the king of Syria who claimed Israelite territory', 'a', '1 Kings 11:17-22 — "That Hadad fled...into Egypt; Hadad being yet a little child...And Hadad found great favour in the sight of Pharaoh...And when Hadad heard in Egypt that David slept with his fathers...Hadad said to Pharaoh, Let me depart."'),
('1 Kings', 11, 'adults', 5, 'What specific promise did Ahijah deliver to Jeroboam about the ten tribes?', 'If Jeroboam walked in God''s statutes and kept His commandments as David had done, God would build him a sure house as He built for David and give him Israel', 'Jeroboam would rule unconditionally over ten tribes forever', 'Ten tribes would follow Jeroboam only if he built them a new temple', 'God would give Jeroboam ten tribes after Solomon''s natural death', 'a', '1 Kings 11:38 — "And it shall be, if thou wilt hearken unto all that I command thee, and wilt walk in my ways...then I will be with thee, and build thee a sure house, as I built for David, and will give Israel unto thee."'),
('1 Kings', 11, 'adults', 6, 'What was Rezon''s origin and how did he come to oppose Solomon?', 'Rezon was a servant of Hadadezer king of Zobah who fled when David defeated his master, gathered men, and reigned in Damascus', 'Rezon was an Edomite prince who unified the southern tribes against Israel', 'Rezon was a renegade Israelite officer who allied with Egypt', 'Rezon was the son of a Philistine king who had been dispossessed by David', 'a', '1 Kings 11:23-24 — "And God stirred him up another adversary, Rezon the son of Eliadah, which fled from his lord Hadadezer king of Zobah...he was an adversary to Israel all the days of Solomon."'),
('1 Kings', 11, 'adults', 7, 'What position did Jeroboam hold under Solomon before his rebellion, and why did Solomon seek to kill him?', 'Solomon had made Jeroboam ruler over all the burden of the house of Joseph, and Solomon sought to kill him after Ahijah''s prophecy', 'Jeroboam was a military commander who refused orders', 'Jeroboam was a priest who had spoken against the temple', 'Jeroboam had led a tax revolt among the northern tribes', 'a', '1 Kings 11:28,40 — "And the man Jeroboam was a mighty man of valour: and Solomon seeing the young man that he was industrious, he made him ruler over all the charge of the house of Joseph...Solomon sought therefore to kill Jeroboam."'),
('1 Kings', 11, 'adults', 8, 'How long did Solomon reign in Jerusalem over all Israel, and where is more information about his acts recorded?', 'Forty years, and the rest of his acts are in the book of the acts of Solomon', 'Thirty years in Hebron and ten in Jerusalem', 'Twenty years recorded in the book of the kings of Israel', 'Fifty years, recorded in the chronicles of Nathan the prophet', 'a', '1 Kings 11:42-41 — "And the time that Solomon reigned in Jerusalem over all Israel was forty years...And the rest of the acts of Solomon, and all that he did, and his wisdom, are they not written in the book of the acts of Solomon?"');
